import { isAnyAdmin } from "@/lib/admin";

async function assertRaioAdmin() {
  const { userId } = await auth();
  if (!userId) return false;
  const user = await currentUser();
  return isAnyAdmin(user?.publicMetadata as Record<string, unknown>);
}

export async function POST() {
  if (!await assertRaioAdmin())
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const prisma = getPrisma();
  let inserted = 0;
  let skipped = 0;

  for (const v of SEED_VEHICLES) {
    try {
      await prisma.vehicle.upsert({
        where: { domain: v.domain },
        update: {},
        create: { name: v.name, domain: v.domain, category: v.category, tier: v.tier, reach: v.reach },
      });
      inserted++;
    } catch {
      skipped++;
    }
  }

  return NextResponse.json({ inserted, skipped, total: SEED_VEHICLES.length });
}

